msg.sensorData = {
    farmId: env.get('FARM_ID') || 'farm_001',
    houseId: env.get('HOUSE_ID') || 'house_001',
    data: { temp_001: 32.5, humidity_001: 65.0 }
};
return msg;

const sensorData = msg.sensorData;
if (!sensorData || !sensorData.farmId || !sensorData.houseId) {
    node.warn('⚠️ sensorData 없음, 평가 건너뜀');
    return null;
}

msg.topic = 'SELECT * FROM automation_rules WHERE farm_id = $1 AND house_id = $2 AND enabled = 1 ORDER BY priority ASC';
msg.payload = [sensorData.farmId, sensorData.houseId];
node.status({ fill: 'blue', shape: 'ring', text: '규칙 조회 중...' });
return msg;

var rules = msg.payload || [];
var sensorData = msg.sensorData;

if (rules.length === 0) {
    node.status({ fill: 'grey', shape: 'dot', text: '활성 규칙 없음' });
    return null;
}

var now = new Date();
var actionsToExecute = [];
var updateMessages = [];

// ── 시간 조건 평가 (timeMode: specific, interval, legacy) ──
function evaluateTimeCondition(cond) {
    var currentDay = now.getDay();
    if (cond.days && cond.days.length > 0 && cond.days.indexOf(currentDay) === -1) {
        return false;
    }
    var nowMinutes = now.getHours() * 60 + now.getMinutes();

    // legacy: timeMode 없고 time 필드만 있으면 단일 시간
    if (!cond.timeMode && cond.time) {
        var parts = cond.time.split(':');
        var target = parseInt(parts[0]) * 60 + parseInt(parts[1]);
        return Math.abs(nowMinutes - target) <= 2;
    }

    // 지정 시간 모드: times 배열 중 하나라도 매칭
    if (cond.timeMode === 'specific') {
        var times = cond.times || [];
        for (var i = 0; i < times.length; i++) {
            var p = times[i].split(':');
            var t = parseInt(p[0]) * 60 + parseInt(p[1]);
            if (Math.abs(nowMinutes - t) <= 2) return true;
        }
        return false;
    }

    // 반복 모드: startTime~endTime 범위에서 interval 간격
    if (cond.timeMode === 'interval') {
        var sp = (cond.startTime || '00:00').split(':');
        var ep = (cond.endTime || '23:59').split(':');
        var start = parseInt(sp[0]) * 60 + parseInt(sp[1]);
        var end = parseInt(ep[0]) * 60 + parseInt(ep[1]);
        var interval = cond.intervalMinutes || 30;
        if (nowMinutes < start - 2 || nowMinutes > end + 2) return false;
        for (var t = start; t <= end; t += interval) {
            if (Math.abs(nowMinutes - t) <= 2) return true;
        }
        return false;
    }

    return false;
}

// 역방향 명령 매핑
var REVERSE_CMD = { 'open': 'close', 'close': 'open', 'on': 'off', 'off': 'on' };

for (var ri = 0; ri < rules.length; ri++) {
    var rule = rules[ri];
    var conditions, actions;
    try { conditions = JSON.parse(rule.conditions); } catch(e) { continue; }
    try { actions = JSON.parse(rule.actions); } catch(e) { continue; }

    // 쿨다운 체크
    if (rule.last_triggered_at) {
        var elapsed = (now.getTime() - new Date(rule.last_triggered_at).getTime()) / 1000;
        if (elapsed < rule.cooldown_seconds) continue;
    }

    // ── 조건 평가 (그룹별 분리 + groupLogic) ──
    var sensorConds = conditions.filter(function(c) { return c.type === 'sensor'; });
    var timeConds = conditions.filter(function(c) { return c.type === 'time'; });

    var sensorResult = true;
    var timeResult = true;

    if (sensorConds.length > 0) {
        var sensorResults = sensorConds.map(function(cond) {
            var val = sensorData.data[cond.sensorId];
            if (val === undefined || val === null) return false;
            switch (cond.operator) {
                case '>': return val > cond.value;
                case '>=': return val >= cond.value;
                case '<': return val < cond.value;
                case '<=': return val <= cond.value;
                case '==': return Math.abs(val - cond.value) < 0.1;
                default: return false;
            }
        });
        sensorResult = (rule.condition_logic === 'OR')
            ? sensorResults.some(function(r) { return r; })
            : sensorResults.every(function(r) { return r; });
    }

    if (timeConds.length > 0) {
        var timeResults = timeConds.map(function(c) { return evaluateTimeCondition(c); });
        timeResult = timeResults.some(function(r) { return r; });
    }

    // groupLogic: 센서 그룹 ↔ 시간 그룹 간 AND/OR
    var triggered = false;
    var groupLogic = rule.group_logic || 'AND';

    if (sensorConds.length > 0 && timeConds.length > 0) {
        triggered = (groupLogic === 'OR') ? (sensorResult || timeResult) : (sensorResult && timeResult);
    } else if (sensorConds.length > 0) {
        triggered = sensorResult;
    } else if (timeConds.length > 0) {
        triggered = timeResult;
    }

    if (triggered) {
        // 이유 텍스트
        var reasonParts = conditions.map(function(cond) {
            if (cond.type === 'sensor') {
                var v = sensorData.data[cond.sensorId];
                return (cond.sensorName || cond.sensorId) + ' ' + v + cond.operator + cond.value;
            }
            if (cond.type === 'time') {
                if (cond.timeMode === 'interval') return '시간 ' + cond.startTime + '~' + cond.endTime + ' ' + cond.intervalMinutes + '분간격';
                if (cond.timeMode === 'specific') return '시간 ' + (cond.times || []).join(',');
                return '시간 ' + (cond.time || '');
            }
            return '';
        }).filter(function(s) { return s; });
        var reason = rule.name + ': ' + reasonParts.join(groupLogic === 'AND' ? ' AND ' : ' OR ');

        for (var ai = 0; ai < actions.length; ai++) {
            var action = actions[ai];
            actionsToExecute.push({
                ruleId: rule.id,
                ruleName: rule.name,
                houseId: rule.house_id,
                deviceId: action.deviceId,
                deviceType: action.deviceType,
                deviceName: action.deviceName || action.deviceId,
                command: action.command,
                duration: action.duration || 0,
                reason: reason
            });
        }

        var newCount = (rule.trigger_count || 0) + 1;
        updateMessages.push({
            topic: 'UPDATE automation_rules SET last_triggered_at = $1, trigger_count = $2, synced = 0 WHERE id = $3',
            payload: [now.toISOString(), newCount, rule.id]
        });

        node.warn('🤖 자동화 실행: ' + rule.name + ' → ' + actions.map(function(a) {
            var ds = a.duration ? ' (' + Math.floor(a.duration/60) + '분' + (a.duration%60) + '초)' : '';
            return a.deviceId + ' ' + a.command + ds;
        }).join(', '));
    }
}

if (actionsToExecute.length === 0) {
    node.status({ fill: 'green', shape: 'dot', text: rules.length + '개 규칙 평가, 실행 없음' });
    if (updateMessages.length === 0) return null;
}

node.status({ fill: 'green', shape: 'dot', text: '실행: ' + actionsToExecute.length + '개 동작' });

// ── 제어 메시지 생성 ──
var controlMessages = actionsToExecute.map(function(action) {
    return {
        control: {
            houseId: action.houseId,
            deviceId: action.deviceId,
            deviceType: action.deviceType,
            command: action.command,
            operator: 'automation',
            requestId: 'auto_' + Date.now() + '_' + Math.random().toString(36).substr(2, 4),
            timestamp: now.toISOString()
        },
        _action: action
    };
});

// ── Duration 기반 역방향 명령 스케줄링 ──
actionsToExecute.forEach(function(action) {
    if (action.duration > 0) {
        var reverseCmd = REVERSE_CMD[action.command];
        if (!reverseCmd) return;

        var timerKey = 'dur_' + action.deviceId;
        var existingTimer = context.get(timerKey);
        if (existingTimer) clearTimeout(existingTimer);

        var timer = setTimeout(function() {
            var reverseMsg = {
                control: {
                    houseId: action.houseId,
                    deviceId: action.deviceId,
                    deviceType: action.deviceType,
                    command: reverseCmd,
                    operator: 'automation_duration',
                    requestId: 'auto_dur_' + Date.now(),
                    timestamp: new Date().toISOString()
                }
            };
            var logMsg = {
                topic: 'INSERT INTO control_logs (timestamp, device_id, command, source, synced) VALUES ($1, $2, $3, $4, 0)',
                payload: [new Date().toISOString(), action.deviceId, reverseCmd, 'automation_duration']
            };
            node.send([[reverseMsg], null, [logMsg]]);
            node.warn('⏱️ Duration 종료: ' + action.deviceId + ' → ' + reverseCmd);
            context.set(timerKey, null);
        }, action.duration * 1000);

        context.set(timerKey, timer);
        node.warn('⏱️ Duration 설정: ' + action.deviceId + ' ' + action.duration + '초 후 → ' + reverseCmd);
    }
});

var logMessages = actionsToExecute.map(function(action) {
    return {
        topic: 'INSERT INTO control_logs (timestamp, device_id, command, source, synced) VALUES ($1, $2, $3, $4, 0)',
        payload: [now.toISOString(), action.deviceId, action.command, 'automation']
    };
});

return [controlMessages.length > 0 ? [controlMessages] : null, updateMessages.length > 0 ? [updateMessages] : null, logMessages.length > 0 ? [logMessages] : null];
